async function main() {
  console.log('🌱 Seeding batch 13 — 20 places...')
  for (const p of places) {
    const s = slug(p.name)
    await prisma.place.upsert({
      where: { slug: s },
      update: {},
      create: { ...p, slug: s },
    })
    console.log('  ✅', p.name)
  }
  console.log('🌱 Batch 13 complete!')
}

main()
